{
  "options": [
    {
      "text": "追问她：你当时在那里做什么？为什么会在那里？",
      "actionId": "choice:ask_what_doing"
    },
    {
      "text": "追问她：你当时是跟着我去的，还是你自己也在那边？",
      "actionId": "choice:ask_following"
    },
    {
      "text": "沉默片刻，换一个方向：你说的那张墓园照片——你还留着底片吗？"
    },
    {
      "text": "后退一步，让她缓一缓——然后看向卡琳娜，问她怎么看"
    }
  ]
}
